	.TITLE	DMP	.PROC	M68000		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	DX0:SM:SM8	; df diverses	.REF	DX0:SM:NTREL	; df noyau temps rel	.REF	DX0:SM:GESMEM	; df gestionnaire de mmoire	.REF	DX0:SM:BIOS	.REF	DX0:SM:FOS	; df file operating system	.REF	DX0:SM:LIB	; df librairie	.REF	DX0:SM:DRIVERS	; df drivers; Variables; ---------	.LOC	0OFLAGS:	.BLKB	2		; flags diversOCHOUT:	.BLKB	2OBUFF:	.BLKB	104*8LGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flags	CLR.W	(A6)+OCHOUT	.W	LIB,?SKPNAM	JUMP,NE	ER	.W	FOS,?DELETE	LOAD.L	D3,#DEFATT	CLR.L	D4	.W	FOS,?CREATE	JUMP,NE	ER	LOAD.W	D3,#2^BOPWR!2^BOPEXCL	.W	FOS,?OPEN	JUMP,NE	ER	LOAD.W	(A6)+OCHOUT,D6	LOAD.L	A4,#R16"HEADER	LOAD.L	D4,#LHEADER	.W	FOS,?WRBYTE	LOAD.B	D0,#1010$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	LOAD.W	D4,#50	.W	NTREL,?DELMS	DEC.B	D0	JUMP,NE	10$;	.W	LIB,?SKPNAM;	JUMP,NE	10$;;	CLR.L	D4;05$:;	LOAD.B	D3,(A3+);	COMP.B	D3,#'0;	JUMP,LO	07$;	COMP.B	D3,#'9;	JUMP,HI	07$;	SUB.B	D3,#'0;	AND.L	D3,#H'FF;	MUL.WU	D4,#10;	ADD.L	D4,D3;	JUMP	05$;;07$:;	TEST.L	D4;	JUMP,EQ	10$;	MUL.WU	D4,#50;	.W	NTREL,?DELMS;10$:	LOAD.B	D3,#BIPBIG	.W	LIB,?BEEP	; fait un joli bruit	LOAD.W	D4,#50	.W	NTREL,?DELMS	LOAD.L	A4,#(A6)+OBUFF	LOAD.W	D4,#LGDIS2	LOAD.W	D1,#TYPDIS	; D1 <-- type DISPLAY	LOAD.W	D2,#H'20	; D2 <-- no driver $DIS_0	.W	BIOS,?DRSTATUS	; lit status de $DIS_0	JUMP,NE ER		; si erreur => ER	CLR.L	D0	COMP.W	(A4)+ODFCAD,#H'100*'U+'L	JUMP,EQ 20$	LOAD.L	D0,#1024*24	COMP.W	(A4)+ODFCAD,#H'100*'U+'R	JUMP,EQ 20$	LOAD.L	D0,#512	COMP.W	(A4)+ODFCAD,#H'100*'D+'L	JUMP,EQ 20$	LOAD.L	D0,#512+1024*24	COMP.W	(A4)+ODFCAD,#H'100*'D+'R	JUMP,EQ 20$	CLR.L	D020$:	LOAD.L	A0,#H'80000	; A0 <-- adresse debut cran	ADD.L	A0,D0	LOAD.W	D2,#512/830$:	LOAD.L	A4,#(A6)+OBUFF	LOAD.W	D0,#840$:	LOAD.L	A1,A0		; A1 <-- ^dbut ligne	LOAD.W	D1,#10450$:	LOAD.B	D3,(A1)	ADD.L	A1,#1024	CALL	QQSWAP	LOAD.B	(A4+),D3	DEC.W	D1	JUMP,NE	50$	INC.L	A0		; A1 <-- ^dbut ligne dessous	DEC.W	D0	JUMP,NE	40$	LOAD.L	A4,#(A6)+OBUFF	LOAD.L	D4,#104*8	LOAD.W	D6,(A6)+OCHOUT	.W	FOS,?WRBYTE	JUMP,NE	ER	DEC.W	D2	JUMP,NE	30$	LOAD.B	D3,#BIPBIG	.W	LIB,?BEEP	JUMP	RETOUR;--------\; QQSWAP  >;--------/; Tourne tous les bits d'un byte,  cause des dfinitions; stupides de l'EPFL, beurk ...; C'est pas du tout optimis, un point c'est tout.; in	D3.B	byte; out	D3.B	byte tourn; mod	D3.LQQSWAP:	PUSHM.L	D0,D1	LOAD.B	D1,#8.50$:	RLX.B	D3	RRX.B	D0	DEC.B	D1	JUMP,NE 50$	LOAD.B	D3,D0		; D3 <-- byte tourn	POPM.L	D0,D1	RETER:	PUSH.W	D7		; sauve l'erreur	.W	LIB,?AFCR	; passe  la ligne	POP.W	D7		; reprend l'erreur	.W	LIB,?AFERROR	; affiche l'erreur	LOAD.B	D3,#BIPERR	.W	LIB,?BEEPRETOUR:	LOAD.W	D6,(A6)+OCHOUT	.W	FOS,?CLOSE	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...HEADER:	.FILLB	12,0	.W	0,32+(104*512)	.FILLB	256-16,0	.B	1,0,1,2	.W	104*8,512	.W	0,104*512	.FILLB	20,0LHEADER	=	.-HEADER	.END	START